-- Time: 2026-03-04 16:09:36.743000 | SPID: 56 | App: Saint
(@P1 varchar(8000),@P2 varchar(8000),@P3 varchar(8000))SET DATEFORMAT YMD;
DECLARE
 @CODPROV VARCHAR(15)= @P1,
 @FECHAINI DATETIME = @P2,
 @FECHAFIN DATETIME = @P3;
/*
 @CODPROV VARCHAR(15)= '8009001',
 @FECHAINI DATETIME = '2022-02-28 00:00:00',
 @FECHAFIN DATETIME = GETDATE();
*/
WITH CTE AS
(
  SELECT 1 TIPO, NROUNICO, NROREGI, CODPROV, FECHAE, FECHAV, FECHAI,
         TIPOCXP, NUMEROD, DOCUMENT, FROMTRAN, RETENIVA, ESRETEN,
         (CANCELE+CANCELC+CANCELT+CANCELI) ABONADO, MONTO, SALDO, 0 AS DETPAGO,
         IIF((CHARINDEX(TIPOCXP,'10.30.60.70')>0) OR (TIPOCXP IN ('31','82')),1,0)*MONTO CREDITO,
         IIF(((CHARINDEX(SUBSTRING(TIPOCXP,1,1),'2.4')>0) OR (TIPOCXP='81')),1,0)*MONTO DEBITO,
         0.0 AS SALDOA
    FROM SAACXP WITH (NOLOCK)
   WHERE (FECHAE>=@FECHAINI) AND (FECHAE<=@FECHAFIN)
)
SELECT F.NROUNICO, F.NROREGI, F.CODPROV, F.TIPO,
       F.FECHAE, F.FECHAV, F.FECHAI,
       F.TIPOCXP,
       (CASE SUBSTRING(F.TIPOCXP,1,1)
         WHEN '1' THEN 'FAC'
         WHEN '2' THEN 'N/D'
         WHEN '3' THEN 'N/C'
         WHEN '4' THEN 'PAG'
         WHEN '5' THEN IIF(F.ABONADO>0,'ADE','N/D')
         WHEN '6' THEN 'GIR'
         WHEN '7' THEN 'CUO'
         WHEN '8' THEN IIF(SUBSTRING(F.TIPOCXP,2,1)='1','RET','REV')
       END) TIPODET,
       F.NUMEROD, F.FROMTRAN, F.RETENIVA, F.ESRETEN,
       F.DOCUMENT, F.DETPAGO,
       F.ABONADO, F.MONTO, F.SALDO, F.DEBITO, F.CREDITO,
       SUM(F.SALDOA-F.DEBITO+F.CREDITO)
           OVER (PARTITION BY F.CODPROV
                     ORDER BY F.FECHAE
                      ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) SALDOACT
  FROM (
         SELECT C.CODPROV, C.FECHAE, C.FECHAV, C.FECHAI,
                0 TIPO, 0 NROUNICO, 0 NROREGI,
                '00' TIPOCXP, '' NUMEROD,
                'SALDO ANTERIOR...' DOCUMENT, 0 FROMTRAN, 0 RETENIVA, 0 ESRETEN, 0 DETPAGO,
                0.0 ABONADO, 0.0 MONTO, 0.0 SALDO, 0.0 DEBITO, 0.0 CREDITO, C.SALDOA
           FROM (
                 SELECT C.CODPROV, C.FECHAE, C.FECHAV, C.FECHAI, C.SALDOA,
                        ROW_NUMBER() OVER (PARTITION BY C.CODPROV
                                               ORDER BY C.CODPROV, C.PRIORITY_ID ASC, C.ORDER_ID ASC) ROWNUMBER
                   FROM (
                         SELECT CODPROV, FECHAE, FECHAV, FECHAI, SALDOACT SALDOA,
                                NULL PRIORITY_ID, ROW_NUMBER() OVER(ORDER BY CODPROV, FECHAE DESC) ORDER_ID
                           FROM SAACXP WITH (NOLOCK)
                          WHERE (FROMTRAN=1) AND (FECHAE<@FECHAINI)
                          UNION ALL
                         SELECT CODPROV, FECHAE, FECHAV, FECHAI, (MTOTOTAL-CONTADO) SALDOA,
                                NULL PRIORITY_ID, ROW_NUMBER() OVER(ORDER BY CODPROV, FECHAE DESC) ORDER_ID
                           FROM SACOMP WITH (NOLOCK)
                          WHERE (FECHAE<@FECHAINI)
                          UNION ALL
                         SELECT P.CODPROV, @FECHAINI-0.0000001 FECHAE, NULL FECHAV, NULL FECHAI, 0 SALDOA,
                                1 PRIORITY_ID, NULL ORDER_ID
                           FROM SAPROV P WITH (NOLOCK)
                          WHERE (P.ACTIVO>0) AND EXISTS( SELECT CODPROV
                                                           FROM CTE
                                                          WHERE (FECHAE>=@FECHAINI) AND (CODPROV=P.CODPROV))
                        ) C
                ) C
          WHERE (C.ROWNUMBER=1)
          UNION ALL
         SELECT F.CODPROV, F.FECHAE, F.FECHAV, F.FECHAI,
                F.TIPO, F.NROUNICO, F.NROREGI,
                F.TIPOCXP, F.NUMEROD, F.DOCUMENT, F.FROMTRAN, F.RETENIVA, F.ESRETEN, F.DETPAGO,
                F.ABONADO, F.MONTO, F.SALDO, F.DEBITO, F.CREDITO, F.SALDOA
           FROM CTE F
          WHERE (F.FECHAE>=@FECHAINI) AND (F.FECHAE<=@FECHAFIN)
       ) F
 WHERE F.CODPROV=@CODPROV
GO

