-- Time: 2026-03-04 21:05:45.853000 | SPID: 74 | App: 
SELECT 
    SAPROD.Descrip, 
    CASE 
        WHEN SATAXPRD.Monto IS NOT NULL THEN SAPROD.Precio1 * (1 + SATAXPRD.Monto / 100) 
        ELSE SAPROD.Precio1 
    END AS Precio1, 
    CASE 
        WHEN SATAXPRD.Monto IS NOT NULL THEN SAPROD.Precio2 * (1 + SATAXPRD.Monto / 100) 
        ELSE SAPROD.Precio2 
    END AS Precio2, 
    CASE 
        WHEN SATAXPRD.Monto IS NOT NULL THEN SAPROD.Precio3 * (1 + SATAXPRD.Monto / 100) 
        ELSE SAPROD.Precio3 
    END AS Precio3, 
    SAPROD.PrecioI1, 
    SAPROD.PrecioI2, 
    SAPROD.PrecioI3, 
    SAPROD.Existen, 
    SAPROD.Descrip3, 
    SAPROD.Refere AS CosPror$, -- Aquí está la columna que pediste agregar
    SATAXPRD.Monto, 
    SAPROD.CodProd AS Cod, 
    GETDATE() AS LastUpdated
FROM 
    dbo.SAPROD 
LEFT OUTER JOIN 
    dbo.SATAXPRD 
ON 
    SAPROD.CodProd = SATAXPRD.CodProd
WHERE 
    SAPROD.Existen > 0 
    AND SAPROD.Activo = 1 
GROUP BY 
    SAPROD.Descrip, 
    SAPROD.Precio1, 
    SAPROD.Precio2, 
    SAPROD.Precio3, 
    SAPROD.PrecioI1, 
    SAPROD.PrecioI2, 
    SAPROD.PrecioI3, 
    SAPROD.Existen, 
    SAPROD.Descrip3, 
    SAPROD.Refere, -- Añadido al GROUP BY para que la consulta sea válida
    SATAXPRD.Monto, 
    SAPROD.CodProd;
GO

