-- Time: 2026-03-04 21:27:26.120000 | SPID: 54 | App: Python
(@P1 nvarchar(4),@P2 nvarchar(4),@P3 nvarchar(4),@P4 nvarchar(4))
            SELECT
              SAACXP.FechaI,
              SAACXP.FechaE,
              SAACXP.FechaV,
              SAPROV.Descrip,
              SAACXP.RetenIVA,
              SAACXP.SaldoAct,
              SAACXP.Monto,
              SAACXP.CodOper,
              SAACXP.MontoNeto,
              SAACXP.Saldo,
              SAACXP.MtoTax,
              SAFACT.MtoPagos,
              SAFACT.SaldoAct AS SaldoAct_SAFACT,
              SAFACT.MtoNCredito,
              SAFACT.MtoNDebito,
              SAFACT.Signo,
              SAFACT.NumeroD AS NumeroD_SAFACT,
              SAACXP.NroCtrol,
              SAFACT.MtoTotal,
              SAFACT.Contado,
              SAFACT.Credito,
              SAACXP.NroUnico,
              SAACXP.CodSucu,
              SAACXP.CodProv,
              SAACXP.NumeroD,
              SAFACT.CodSucu AS CodSucu_SAFACT,
              SAFACT.TipoFac,
              SAPAGCXP.NumeroD AS NumeroD_SAPAGCXP,
              dt_emision.dolarbcv AS TasaEmision,
              dt_actual.dolarbcv AS TasaActual,
              PP.ID AS Plan_ID,
              PP.Banco AS Plan_Banco,
              PP.FechaPlanificada AS Plan_Fecha
            FROM dbo.SAACXP
            LEFT OUTER JOIN dbo.SAPAGCXP ON SAACXP.NroUnico = SAPAGCXP.NroUnico
            LEFT OUTER JOIN dbo.SAPROV ON SAACXP.CodProv = SAPROV.CodProv
            LEFT OUTER JOIN dbo.SAIPACXP ON SAACXP.NroUnico = SAIPACXP.NroUnico
            LEFT OUTER JOIN dbo.SAFACT ON SAACXP.NroUnico = SAFACT.NroUnico
            OUTER APPLY (
                SELECT TOP 1 dolarbcv 
                FROM EnterpriseAdmin_AMC.dbo.dolartoday 
                WHERE CAST(fecha AS DATE) <= CAST(SAACXP.FechaE AS DATE)
                ORDER BY fecha DESC
            ) dt_emision
            OUTER APPLY (
                SELECT TOP 1 dolarbcv 
                FROM EnterpriseAdmin_AMC.dbo.dolartoday 
                WHERE dolarbcv IS NOT NULL
                ORDER BY id DESC
            ) dt_actual
            LEFT OUTER JOIN EnterpriseAdmin_AMC.Procurement.PagosPlanificados PP
                ON SAACXP.NroUnico = PP.NroUnico
            WHERE (SAACXP.NumeroD LIKE @P1
               OR SAFACT.NumeroD LIKE @P2
               OR SAPAGCXP.NumeroD LIKE @P3
               OR SAPROV.Descrip LIKE @P4)
                AND SAACXP.FechaE >= DATEADD(month, -4, GETDATE())
            ORDER BY SAACXP.FechaE DESC
GO

