-- Time: 2026-03-04 21:53:44.693000 | SPID: 59 | App: 
-- We use a Common Table Expression (CTE) to make it easier to filter duplicates.
-- This CTE first filters the records and then numbers them to identify the most recent one.
WITH AuditoriaEnumerada AS (
    SELECT
        AuditID,
        Cod,
        InicioConteo,
        -- ROW_NUMBER() is used to identify the most recent record for each 'Cod'.
        -- PARTITION BY Cod: groups rows by the value of 'Cod'.
        -- ORDER BY InicioConteo DESC, AuditID DESC: orders each group by date and then by ID,
        -- from newest to oldest, to consistently find the most recent record.
        -- As a result, the most recent record for each 'Cod' gets row number (Rownum) 1.
        ROW_NUMBER() OVER(PARTITION BY Cod ORDER BY InicioConteo DESC, AuditID DESC) AS Rownum
    FROM
        EnterpriseAdmin_AMC.Procurement.InvAudit
    WHERE
        -- Condition 1: Include only records that have not been verified.
        Verificado = 0
        -- Condition 2: Include only records from today or yesterday.
        AND CAST(InicioConteo AS DATE) IN (
            CAST(GETDATE() AS DATE), -- Current server date
            CAST(DATEADD(day, -1, GETDATE()) AS DATE) -- Previous day
        )
)
-- Finally, select only the required columns from the CTE.
SELECT
    AuditID,
    Cod,
    InicioConteo
FROM
    AuditoriaEnumerada
-- Keep only row number 1 from each group, which is the most recent record.
WHERE
    Rownum = 1;
GO

-- Time: 2026-03-04 22:02:00.593000 | SPID: 67 | App: 
create procedure sys.sp_datatype_info_100
(
    @data_type int = 0,
    @ODBCVer tinyint = 2
)
as
    declare @mintype int
    declare @maxtype int

    set @ODBCVer = isnull(@ODBCVer, 2)
    if @ODBCVer < 3 -- includes ODBC 1.0 as well
        set @ODBCVer = 2
    else
        set @ODBCVer = 3

    if @data_type = 0
    begin
        select @mintype = -32768
        select @maxtype = 32767
    end
    else
    begin
        select @mintype = @data_type
        select @maxtype = @data_type
    end

    select
        TYPE_NAME           = v.TYPE_NAME,
        DATA_TYPE           = v.DATA_TYPE,
        PRECISION           = v.PRECISION,
        LITERAL_PREFIX      = v.LITERAL_PREFIX,
        LITERAL_SUFFIX      = v.LITERAL_SUFFIX,
        CREATE_PARAMS       = v.CREATE_PARAMS,
        NULLABLE            = v.NULLABLE,
        CASE_SENSITIVE      = v.CASE_SENSITIVE,
        SEARCHABLE          = v.SEARCHABLE,
        UNSIGNED_ATTRIBUTE  = v.UNSIGNED_ATTRIBUTE,
        MONEY               = v.MONEY,
        AUTO_INCREMENT      = v.AUTO_INCREMENT,
        LOCAL_TYPE_NAME     = v.LOCAL_TYPE_NAME,
        MINIMUM_SCALE       = v.MINIMUM_SCALE,
        MAXIMUM_SCALE       = v.MAXIMUM_SCALE,
        SQL_DATA_TYPE       = v.SQL_DATA_TYPE,
        SQL_DATETIME_SUB    = v.SQL_DATETIME_SUB,
        NUM_PREC_RADIX      = v.NUM_PREC_RADIX,
        INTERVAL_PRECISION  = v.INTERVAL_PRECISION,
        USERTYPE            = v.USERTYPE

    from
        sys.spt_datatype_info_view v

    where
        v.DATA_TYPE between @mintype and @maxtype and
        v.ODBCVer = @ODBCVer

    order by 2, 12, 11, 20
GO

-- Time: 2026-03-04 22:04:14.463000 | SPID: 67 | App: Python
(@P1 nvarchar(20),@P2 nvarchar(20))
            SELECT 
               FORMAT(COALESCE(PP.FechaPlanificada, SAACXP.FechaV), 'yyyy-MM-dd') AS Periodo,
               SUM(SAACXP.Saldo) AS SaldoProyectado
            FROM dbo.SAACXP
            LEFT JOIN EnterpriseAdmin_AMC.Procurement.PagosPlanificados PP ON SAACXP.NroUnico = PP.NroUnico
            WHERE SAACXP.Saldo > 0 AND CAST(COALESCE(PP.FechaPlanificada, SAACXP.FechaV) AS DATE) >= @P1 AND CAST(COALESCE(PP.FechaPlanificada, SAACXP.FechaV) AS DATE) <= @P2
            GROUP BY FORMAT(COALESCE(PP.FechaPlanificada, SAACXP.FechaV), 'yyyy-MM-dd')
            ORDER BY Periodo
GO

